import{bV as s,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const _=JSON.parse('{"title":"自动组织生成","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/自动组织生成.md","filePath":"mumuainovel/自动组织生成.md","lastUpdated":1777768110000}'),t={name:"mumuainovel/自动组织生成.md"};function e(i,n,o,c,u,q){return a(),p("div",null,[...n[0]||(n[0]=[l(`<h1 id="自动组织生成" tabindex="-1">自动组织生成 <a class="header-anchor" href="#自动组织生成" aria-label="Permalink to &quot;自动组织生成&quot;">​</a></h1><blockquote><p>模板键: <code>AUTO_ORGANIZATION_GENERATION</code> 分类: 自动组织引入 描述: 根据剧情需求自动生成新组织的完整设定 参数: [&quot;title&quot;, &quot;genre&quot;, &quot;theme&quot;, &quot;time_period&quot;, &quot;location&quot;, &quot;atmosphere&quot;, &quot;rules&quot;, &quot;existing_organizations&quot;, &quot;existing_characters&quot;, &quot;plot_context&quot;, &quot;organization_specification&quot;, &quot;mcp_references&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是专业的世界构建师，擅长根据剧情需求创建完整的组织/势力设定。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【生成任务】</span></span>
<span class="line"><span>为小说生成新组织的完整设定，包括基本信息、组织特性、背景历史和成员结构。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【命名要求】</span></span>
<span class="line"><span>如果【已有组织】中存在组织，新组织的命名风格必须与已有组织保持一致。</span></span>
<span class="line"><span>参考已有组织的名称规律（用词习惯、字数、文化风格），生成符合同一世界观的新组织名称。</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;project priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【项目信息】</span></span>
<span class="line"><span>书名：{title}</span></span>
<span class="line"><span>类型：{genre}</span></span>
<span class="line"><span>主题：{theme}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【世界观】</span></span>
<span class="line"><span>时间背景：{time_period}</span></span>
<span class="line"><span>地理位置：{location}</span></span>
<span class="line"><span>氛围基调：{atmosphere}</span></span>
<span class="line"><span>世界规则：{rules}</span></span>
<span class="line"><span>&lt;/project&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;context priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【已有组织】</span></span>
<span class="line"><span>{existing_organizations}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【已有角色】</span></span>
<span class="line"><span>{existing_characters}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【剧情上下文】</span></span>
<span class="line"><span>{plot_context}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【组织规格要求】</span></span>
<span class="line"><span>{organization_specification}</span></span>
<span class="line"><span>&lt;/context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;mcp_context priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>【MCP工具参考】</span></span>
<span class="line"><span>{mcp_references}</span></span>
<span class="line"><span>&lt;/mcp_context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;naming_guidelines priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【各类型组织命名风格】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**现代都市**：公司用全称/简称（盛华集团、锐思科技）、机构用正式名称（市公安局、第一人民医院）</span></span>
<span class="line"><span>**玄幻仙侠**：用意境词+门派词（天剑宗、幽冥殿、星辰阁、万兽山庄）</span></span>
<span class="line"><span>**科幻**：用编号/代号/功能名（第七舰队、量子研究所、新星联邦）</span></span>
<span class="line"><span>**历史古代**：用朝代+职能（锦衣卫、漕帮、翰林院）</span></span>
<span class="line"><span>**奇幻魔法**：用象征词+组织词（银月骑士团、暗影议会、龙语学院）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【命名原则】</span></span>
<span class="line"><span>- 参考已有组织的命名风格，保持高度一致</span></span>
<span class="line"><span>- 名称要有文化代入感，不要用现代词汇套古代背景</span></span>
<span class="line"><span>- 组织名称长度2-6个字为佳</span></span>
<span class="line"><span>- 如果已有组织名称都是&quot;XX宗/XX阁/XX殿&quot;格式，新组织也用相同格式</span></span>
<span class="line"><span>- 如果已有组织名称都是现代公司名格式，新组织也用相同格式</span></span>
<span class="line"><span>&lt;/naming_guidelines&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;requirements priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【核心要求】</span></span>
<span class="line"><span>1. 组织必须符合剧情需求和世界观设定</span></span>
<span class="line"><span>2. 组织要有明确的目的、结构和特色</span></span>
<span class="line"><span>3. 组织特性、背景要有深度和独特性</span></span>
<span class="line"><span>4. 外在表现要具体生动</span></span>
<span class="line"><span>5. 考虑与已有组织的关系和互动</span></span>
<span class="line"><span>6. 如果需要，可以建议将现有角色加入组织</span></span>
<span class="line"><span>&lt;/requirements&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>返回纯JSON对象：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>&quot;name&quot;: &quot;组织名称（必须符合已有组织的命名风格）&quot;,</span></span>
<span class="line"><span>&quot;is_organization&quot;: true,</span></span>
<span class="line"><span>&quot;role_type&quot;: &quot;supporting&quot;,</span></span>
<span class="line"><span>&quot;organization_type&quot;: &quot;组织类型（帮派/门派/公司/政府/家族/神秘组织等）&quot;,</span></span>
<span class="line"><span>&quot;personality&quot;: &quot;组织特性的详细描述（150-200字）：运作方式、核心理念、行事风格、文化价值观&quot;,</span></span>
<span class="line"><span>&quot;background&quot;: &quot;组织背景故事（200-300字）：建立历史、发展历程、重要事件、当前地位&quot;,</span></span>
<span class="line"><span>&quot;appearance&quot;: &quot;外在表现（100-150字）：总部位置、标志性建筑、组织标志、成员着装&quot;,</span></span>
<span class="line"><span>&quot;organization_purpose&quot;: &quot;组织目的和宗旨：明确目标、长期愿景、行动准则&quot;,</span></span>
<span class="line"><span>&quot;power_level&quot;: 75,</span></span>
<span class="line"><span>&quot;location&quot;: &quot;所在地点：主要活动区域、势力范围&quot;,</span></span>
<span class="line"><span>&quot;motto&quot;: &quot;组织格言或口号&quot;,</span></span>
<span class="line"><span>&quot;color&quot;: &quot;组织代表颜色&quot;,</span></span>
<span class="line"><span>&quot;traits&quot;: [&quot;特征1&quot;, &quot;特征2&quot;, &quot;特征3&quot;],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;initial_members&quot;: [</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;character_name&quot;: &quot;已存在的角色名称&quot;,</span></span>
<span class="line"><span>  &quot;position&quot;: &quot;职位名称&quot;,</span></span>
<span class="line"><span>  &quot;rank&quot;: 8,</span></span>
<span class="line"><span>  &quot;loyalty&quot;: 80,</span></span>
<span class="line"><span>  &quot;joined_at&quot;: &quot;加入时间（可选）&quot;,</span></span>
<span class="line"><span>  &quot;status&quot;: &quot;active&quot;</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span>],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;organization_relationships&quot;: [</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;target_organization_name&quot;: &quot;已存在的组织名称&quot;,</span></span>
<span class="line"><span>  &quot;relationship_type&quot;: &quot;盟友/敌对/竞争/合作/从属等&quot;,</span></span>
<span class="line"><span>  &quot;description&quot;: &quot;关系的具体描述&quot;</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span>]</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【数值范围】</span></span>
<span class="line"><span>- power_level：0-100的整数，表示在世界中的影响力</span></span>
<span class="line"><span>- rank：0到10（职位等级）</span></span>
<span class="line"><span>- loyalty：0到100（成员忠诚度）</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 符合剧情需求和世界观设定</span></span>
<span class="line"><span>✅ 组织要有独特的定位和价值</span></span>
<span class="line"><span>✅ character_name必须精确匹配【已有角色】</span></span>
<span class="line"><span>✅ target_organization_name必须精确匹配【已有组织】</span></span>
<span class="line"><span>✅ 组织能够推动剧情发展</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【命名约束】</span></span>
<span class="line"><span>✅ 如果已有组织存在，新组织名称风格必须与已有组织一致</span></span>
<span class="line"><span>✅ 组织名称必须符合世界观文化背景</span></span>
<span class="line"><span>✅ 参考已有组织的命名规律（用词习惯、字数、文化风格）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 输出markdown标记</span></span>
<span class="line"><span>❌ 在描述中使用特殊符号</span></span>
<span class="line"><span>❌ 引用不存在的角色或组织</span></span>
<span class="line"><span>❌ 创建功能与现有组织重复的组织</span></span>
<span class="line"><span>❌ 创建对剧情没有实际作用的组织</span></span>
<span class="line"><span>❌ 忽略已有组织命名风格，随意编造名称</span></span>
<span class="line"><span>❌ 古代背景使用现代组织名（如&quot;XX科技&quot;&quot;XX集团&quot;）</span></span>
<span class="line"><span>❌ 现代背景使用古代门派名（如&quot;XX宗&quot;&quot;XX阁&quot;）</span></span>
<span class="line"><span>❌ 使用与世界观不匹配的词汇命名</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const g=s(t,[["render",e]]);export{_ as __pageData,g as default};
